def fatorial(n):
    if not isinstance(n, int) or n < 0:
        raise ValueError("O argumento deve ser um numero inteiro maior ou igual a zero")

    elif n == 0 or n == 1:
        return 1     # Casos base do fatorial. Se 'n' for 0, retorna 1; se é 1, também retorna 1...
                      # pois o produto de um numero com todos os numeros ate ele eh sempre esse mesmo numero (e isso define a propriedade do fatorial).
    else:             # Se 'n' for maior que 0. Então, retorna n vezes chamaremos na recursao o produto de "n" com os fatores anteriores até zero...
        return n * fatorial(n-1)   // ... e assim sucessivamente pra todo 'n' maior que 0.
